    private fun validateCaller(intent: Intent): Boolean {
        val callerPackage = intent.getStringExtra(EXTRA_CALLER_PACKAGE)
        
        if (callerPackage.isNullOrEmpty()) {
            Log.w(TAG, "Caller package not provided")
