        try {
            val callerUid = packageManager.getApplicationInfo(callerPackage, 0).uid
            val callingUid = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.Q) {
                intent.getIntExtra("calling_uid", -1)
